```powershell
# PowerShell 6+ supporte SSH comme transport

# Connexion SSH (PS 6+)
Enter-PSSession -HostName "linux-server" -UserName "alice" -SSHTransport

# Session SSH
$session = New-PSSession -HostName "linux-server" `
    -UserName "alice" `
    -KeyFilePath "~/.ssh/id_rsa" `
    -SSHTransport

Invoke-Command -Session $session -ScriptBlock { uname -a }

# Sans SSH : exécuter bash via Invoke-Command
Invoke-Command -HostName "linux" -UserName "alice" -ScriptBlock {
    bash -c 'df -h / | tail -1'
}

# Résumé multi-plateforme
$machines = @(
    @{HostName='win-srv'; Transport='WsMan'},
    @{HostName='linux-srv'; Transport='SSH'; UserName='admin'}
)

foreach ($m in $machines) {
    $params = if ($m.Transport -eq 'SSH') {
        @{HostName=$m.HostName; UserName=$m.UserName; SSHTransport=$true}
    } else {
        @{ComputerName=$m.HostName}
    }
    Invoke-Command @params -ScriptBlock { $env:COMPUTERNAME ?? hostname }
}
```

